<main class="vk-messenger" data-chat-id="<?=(int)($chat['id']??0)?>" data-event-cursor="<?=(int)$cursor?>"><?=\Kovcheg\View::partial('site-sidebar',['active'=>'messages'])?><aside class="vk-dialogs"><header class="vk-dialog-head"><input type="search" data-global-search placeholder="Поиск"></header><div class="vk-dialog-list" data-chat-items><?php foreach($chats as $item):?><a class="vk-dialog <?=($chat&&$item['id']===$chat['id'])?'active':''?>" data-chat-item="<?=(int)$item['id']?>" href="<?=e(chat_public_url($item,\Kovcheg\Auth::id()))?>"><?=chat_avatar_html($item,$item['avatar_user']??null,'avatar')?><span><b><?=e($item['display_title'])?></b><small><?=e($item['last_body']?:'Нет сообщений')?></small></span><time><?=e(human_time($item['last_at']))?></time></a><?php endforeach;?></div></aside><section class="vk-conversation <?=$chat?'':'empty'?>"><div class="conversation-shell" data-conversation-shell><?=\Kovcheg\View::partial('conversation-shell',compact('chat','messages','members','stickers','currentMembership','permissions','invites','joinRequests'))?></div></section></main>
